mapper.select:
/** 시험지 게시판 리스트 */ SELECT a.* ,(select count(*) from t_test_question where test_tmpl_seq = a.test_tmpl_seq) qstn_cnt ,(select user_nm from t_user_info where user_id = a.reg_id) reg_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg1_seq) ctg1_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg2_seq) ctg2_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg3_seq) ctg3_nm FROM t_test_tmpl a where 1=1
ORDER BY REG_DE DESC
LIMIT #{firstIndex},#{rowCnt}

/** 교육 > 시험지 리스트 */ SELECT a.* ,b.test_tmpl_nm ,c.state test_result_state,c.pass_yn ,(select count(*) from t_test_question where test_tmpl_seq = b.test_tmpl_seq) qstn_cnt ,(select user_nm from t_user_info where user_id = a.reg_id) reg_nm ,(select count(*) from t_test_result where test_seq = a.test_seq and state in (2,3) ) test_result_cnt ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = b.ctg1_seq) ctg1_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = b.ctg2_seq) ctg2_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = b.ctg3_seq) ctg3_nm ,(select sum(marks) from t_test_question where test_tmpl_seq = b.test_tmpl_seq) tot_marks ,(select count(*) from t_lecture_stdnt where edu_seq = a.edu_seq and state = 2 ) test_stdnt_cnt ,(select sub_nm from t_lecture_subject where sub_seq = a.sub_seq) sub_nm FROM t_test a left join t_test_tmpl b on a.test_tmpl_seq = b.test_tmpl_seq left join (select * from t_test_result where user_id = #{userId}) c on a.test_seq = c.test_seq where 1=1 and a.edu_seq = #{eduSeq}
and a.status in (1,3)
and a.status = #{status}
ORDER BY a.REG_DE
LIMIT #{firstIndex},#{rowCnt}

/** 교육 > 시험지 갯수 */
SELECT count(a.test_seq)
FROM t_test a
left join t_test_tmpl b on a.test_tmpl_seq = b.test_tmpl_seq
where 1=1
and a.edu_seq = #{eduSeq}


and a.status in (1,3)


and a.status = #{status}

/** 학생의 시험문제(답변지) 목록 */
select d.qstn_seq,d.qstn_nm,d.qstn_tp,d.diff_type,d.qstn_fn_rnm,d.qstn_desc,d.qstn_str,d.ans_desc
,d.fill_blank as 'fill_blank_co'
,b.tq_seq,b.marks
,c.answered_yn,c.optn,c.fill_blank,c.answer,c.ord,c.ch_ord,c.marks_get
from t_test a
inner join t_test_question b on a.test_tmpl_seq = b.test_tmpl_seq
inner join t_question d on b.qstn_seq = d.qstn_seq
left join t_test_answer c on a.test_seq = c.test_seq and b.tq_seq = c.tq_seq
where a.test_seq = #{testSeq}
and c.user_id = #{userId}

	and c.tq_seq = #{tqSeq}

order by c.ord

/** 학생의 시험문제 보기목록 */
select b.*
,a.tq_seq,a.test_tmpl_seq
from t_test_question a 
inner join t_question_choice b on a.qstn_seq = b.qstn_seq
where a.test_tmpl_seq = #{testTmplSeq}

and b.ch_ans_yn = #{chAnsYn}


	and a.tq_seq = #{tqSeq}

/** 시험결과 학생조회 */ select a.sub_seq ,b.user_id,b.user_nm ,c.start_de,c.end_de,c.tot_marks,c.marks,c.pass_yn,c.achv_lvl,c.state test_result_state ,(select login_id from t_user_info where user_id = b.user_id) login_id ,(select user_nm from t_user_info where user_id = c.check_id) check_nm from t_test a inner join t_lecture_stdnt b on a.edu_seq = b.edu_seq left join t_test_result c on a.test_seq = c.test_seq and b.user_id = c.user_id where a.edu_seq = #{eduSeq}
and a.test_seq = #{testSeq}
and b.state = 2 and b.user_id = #{userId}
